document.addEventListener('DOMContentLoaded', function() {
    // Select all scripts generated by Django's json_script
    const dataScripts = document.querySelectorAll('script[type="application/json"]');

    dataScripts.forEach(script => {
        const rawContent = script.textContent.trim();
        if (!rawContent) return; 

        try {
            const data = JSON.parse(rawContent);

            // Logic check: only process if it has our chart data structure
            if (!data.id || !data.series) return;

            // Target the div we created in the loop
            // Note: we use the 'key' (script.id) to find the container
            const containerId = `chart_${script.id}`;
            const container = document.getElementById(containerId);

            if (container) {
                const options = {
                    colors: ["#a1a1a4", "#FF1654"],
                    series: [{
                        name: 'Total KB',
                        type: 'column',
                        data: data.col
                    }, {
                        name: 'Cefoxitin Resistance %',
                        type: 'line',
                        data: data.series
                    }],
                    chart: {
                        height: 300,
                        type: 'line',
                        width: '100%', 
                        redrawOnParentResize: true
                    },
                    zoom: {
                        enabled: false,
                    },
                    title: { text: data.title },
                    xaxis: { 
                        categories: data.xlabel,
                        title: {
                            text: 'Visit Number'
                        }
                    },
                    yaxis: [
                        { title: { text: 'Total KB' } },
                        { 
                            opposite: true, 
                            title: { text: 'Cefoxitin Resistance %' },
                            max: 100,
                            min: 0
                        }
                    ]
                };

                const chart = new ApexCharts(container, options);
                chart.render();
            }
        } catch (e) {
            console.error("Error parsing chart data:", e);
        }
    });
});